var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"여기가 마지막인가?!","JPN":"ここが最後か！？","ENG":"Is this the last one?","TWN":"這是最後一個了嗎？！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"제기랄, 정말 힘 하나는 무식하게 세구만......","JPN":"クソ、力だけはマジ半端ないな……","ENG":"Geez, you're almost inhumanly strong.","TWN":"該死，你的力量是真的強……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"아직 하나 남았어.","JPN":"まだ一つ残ってる。","ENG":"There's one more after this.","TWN":"還剩一個。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"그래도 이 정도면 차원 폭풍도 꽤 약해진 것 같은데?","JPN":"けど、次元の暴風もだいぶ弱まったみたいだ。","ENG":"But the dimensional storm already has grown pretty weak.","TWN":"但光是這樣，現在次元風暴也就減弱很多了吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"굳이 남은 침식 쐐기까지 처치할 필요는 없는 거 아닌가?","JPN":"残りの侵食楔まで根絶するまでもないんじゃないか？","ENG":"Do we really need to finish the remaining Corrupted Wedge?","TWN":"不需要非把最後一個侵蝕釘也解決掉吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"쓸데없는 후환을 남겨놓을 필요는 없지.","JPN":"余計な火種を残していいことなんてない。","ENG":"Yes, it could come back to bite us later.","TWN":"我們沒有必要留下後患。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"여기까지 왔는데 조금만 더 고생하자고.","JPN":"ここまで来たんだから、もう少しだけがんばろうぜ。","ENG":"We came this far. We just need to put forth our strength for a little longer.","TWN":"都到這個地步了，再稍微辛苦一下吧。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"젠장, 고생이라면 이미 충분히 했다고!","JPN":"ちくしょう、もう十分がんばったんだよ！　","ENG":"Goddamnit, but for how long? I'm tired of this!","TWN":"該死，我已經夠辛苦了耶！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"등대 쪽에 있는 네 동료들도 기다리고 있을 텐데......","JPN":"灯台にいるあんたの仲間たちも待ってるだろうし……","ENG":"Your teammates are waiting for you by the Lighthouse.","TWN":"在燈塔那裡的同伴應該也在等我們……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"여하간 적당히 하고 돌아가는 게 좋지 않겠어?","JPN":"この辺にして、戻ったほうが良いんじゃないのか？","ENG":"Why don't we hurry things up here and go back?","TWN":"不管怎樣，我們做得差不多就回去吧？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"아, 아니 꼭 돌아가고 싶다는 뜻은 아니고......","JPN":"い、いや、必ずしも戻りたいという話じゃないけど……","ENG":"I-I mean, it's not that I really want to go back...","TWN":"不、不是，也不是說非要回去……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"왜 그렇게 무섭게 노려보고 그래?","JPN":"なんだよそんな怖い目で睨みつけて。","ENG":"So stop glaring at me like that.","TWN":"幹嘛這麼可怕地瞪著我啊？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"가자고! 가면 되잖아?!","JPN":"行くよ！　行けばいいんだろ！？","ENG":"Okay, let's go!","TWN":"我去啦！我去總行了吧！"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"마지막 침식 쐐기가 있는 방향이...... 혹시 저쪽인가?","JPN":"最後の侵食楔があるのは……もしかして、あっちか？","ENG":"Is the last Corrupted Wedge... that way?","TWN":"最後一個侵蝕釘所在的方向……是在那邊嗎？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACOB_NPC_NULL_NULL","text":{"KOREA":"어? 그러고 보니...... 그런데? 왜?","JPN":"へ？　そう言われてみれば……そうだな。どうした？","ENG":"Huh? Now that I think of it, yes. Why?","TWN":"咦？這麼說來……等等？怎麼回事？"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JACOB_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"뭔가 다가오고 있어.","JPN":"何かが近づいてきてる。","ENG":"Something's coming.","TWN":"有什麼東西過來了。"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"이건...... 설마......","JPN":"これは……まさか……","ENG":"It's... not...","TWN":"這個……難道是……"},"stage":{"bg":"COUNTERSIDE_SPACE","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};